# scripts/triage_sarif.py
# Reads SARIF output and prints a prioritized finding list, filtering out known false positives
import json, sys
from pathlib import Path

KNOWN_FP_RULES = {
    "B101",  # assert — acceptable in test code
    "B404",  # subprocess import — intentional tool runner
}

SEVERITY_ORDER = {"error": 0, "warning": 1, "note": 2}


def load_sarif(path):
    with open(path) as f:
        return json.load(f)


def extract_findings(sarif):
    findings = []
    for run in sarif.get("runs", []):
        rules = {r["id"]: r for r in run.get("tool", {}).get("driver", {}).get("rules", [])}
        for result in run.get("results", []):
            rule_id = result.get("ruleId", "")
            if rule_id in KNOWN_FP_RULES:
                continue
            severity = result.get("level", "warning")
            location = result.get("locations", [{}])[0]
            uri = location.get("physicalLocation", {}).get("artifactLocation", {}).get("uri", "?")
            line = location.get("physicalLocation", {}).get("region", {}).get("startLine", 0)
            message = result.get("message", {}).get("text", "")
            findings.append({
                "severity": severity,
                "rule_id": rule_id,
                "location": f"{uri}:{line}",
                "message": message[:120],
            })
    return sorted(findings, key=lambda f: SEVERITY_ORDER.get(f["severity"], 3))


if __name__ == "__main__":
    all_findings = []
    for sarif_path in Path("results").glob("*.sarif"):
        all_findings.extend(extract_findings(load_sarif(sarif_path)))

    if not all_findings:
        print("No actionable findings.")
        sys.exit(0)

    print(f"{'SEV':<8} {'RULE':<30} {'LOCATION':<40} MESSAGE")
    print("-" * 110)
    for f in all_findings:
        print(f"{f['severity']:<8} {f['rule_id']:<30} {f['location']:<40} {f['message']}")

    errors = [f for f in all_findings if f["severity"] == "error"]
    if errors:
        print(f"\n{len(errors)} ERROR-level finding(s) — failing build")
        sys.exit(1)
